import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      {/* Popular Products */}
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        🔥 Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "center" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                borderRadius: "10px",
                padding: "15px",
                background: "#fff",
                height: "200px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3 style={{ fontSize: "16px", margin: "10px 0 5px" }}>
              {item.name}
            </h3>
            <p style={{ fontSize: "14px", color: "#555" }}>
              {item.description}
            </p>
            <p style={{ fontWeight: "bold", margin: "5px 0" }}>
              ${item.price}
            </p>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#9d5b2e",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>

      {/* ✨ Featured Section Under Popular Products */}
      <div style={{ marginTop: "60px" }}>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          ✨ Featured Picks
        </h2>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(3, 1fr)",
            gap: "25px",
            maxWidth: "1000px",
            margin: "0 auto",
          }}
        >
          {/* Example featured cards */}
          {[
            {
              title: "Unparalleled Sound",
              desc: "Experience crystal-clear audio with premium headphones.",
              img: "https://via.placeholder.com/400x400?text=Headphones",
            },
            {
              title: "Stay Connected",
              desc: "Compact and stylish earphones for every occasion.",
              img: "https://via.placeholder.com/400x400?text=Earphones",
            },
            {
              title: "Power in Every Pixel",
              desc: "Shop the latest laptops for work, gaming, and more.",
              img: "https://via.placeholder.com/400x400?text=Laptop",
            },
          ].map((card, index) => (
            <div
              key={index}
              style={{
                position: "relative",
                height: "300px",
                borderRadius: "12px",
                backgroundImage: `url(${card.img})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                overflow: "hidden",
                display: "flex",
                alignItems: "flex-end",
                color: "#fff",
                padding: "20px",
              }}
            >
              <div
                style={{
                  background: "rgba(0,0,0,0.6)",
                  borderRadius: "10px",
                  padding: "15px",
                  width: "100%",
                }}
              >
                <h3 style={{ margin: "0 0 10px" }}>{card.title}</h3>
                <p style={{ fontSize: "14px", marginBottom: "10px" }}>
                  {card.desc}
                </p>
                <button
                  style={{
                    padding: "8px 15px",
                    border: "none",
                    borderRadius: "6px",
                    background: "#9d5b2e",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  Buy Now ↗
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default PopularProducts;
